var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"길이 끝났어. 여기가 숲의 출구인 것 같아.","JPN":"道が途切れてる。ここが森の出口みたい。","ENG":"This is the end of the trail. I guess this is the forest's exit.","TWN":"沒路了，這裡應該就是森林的出口。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 저건…….","JPN":"でもあれは……","ENG":"But isn't that…","TWN":"那個是……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"왜 그래? 밖에 뭐 신기한 거라도 있어?","JPN":"どうしたの？　外になにかあるの？","ENG":"What's wrong? See something out there?","TWN":"怎麼了？外面有什麼厲害的東西嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"잠깐, 저게 대체 뭐야……?","JPN":"待って、アレはいったい何……？","ENG":"Hang on… What is that?","TWN":"那個，是什麼……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"왜 그래, 편입생들? 겁쟁이들처럼 굳어서는?","JPN":"どうしたのよ、編入生ども。腰抜けみたいにぼーっとして。","ENG":"What's up, transfer students? You're all frozen like cowards.","TWN":"插班生你們幹嘛？像個膽小鬼似地僵在那裡幹嘛？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"저리 비켜! 이 뉴 나이엘 님이 앞장서 주지!","JPN":"どいて！　このNewナイエル様が先に行くわ！","ENG":"Step aside! The New Naielle will lead the way!","TWN":"都給我讓開！換我新奈爾來帶頭！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"저, 저거…… 설마 성이야?","JPN":"あ、あれは……もしかしてお城なの？","ENG":"W-what the… Is that a castle?","TWN":"那……那個是城堡？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"맞아. 그것도 엄청 오래된 성 같은데……","JPN":"そうだね。それもすごく古いお城みたい。","ENG":"I know, right? And it looks super old too…","TWN":"沒錯，而且看起來是年代久遠的城堡……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그 선생은 뭐 중세 테마파크라도 만들고 싶었나?","JPN":"あの先生は何者？　中世のテーマパークでも作りたかったのかな？","ENG":"So... Has this guy been working on some kind of medieval theme park here?","TWN":"那個老師是想蓋一座中世紀主題樂園嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"배짱이 대단한데?!","JPN":"大した度胸ね！","ENG":"I applaud his ambition!","TWN":"很厲害欸！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그 취향, 이 나이엘 님께서 인정해 주지!","JPN":"その趣味、このナイエル様が認めてやるわ！","ENG":"I must say I approve!","TWN":"我認同他的想法！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아니. 아카데미 교사 월급으로 그게 가능할 리가 없잖아.","JPN":"いやいや、アカデミー教師の給料でそんなことできっこないわ。","ENG":"Hang on. There's no way he could afford to build a castle on a teacher's salary.","TWN":"拜託，光憑一個學院老師的薪水怎麼可能蓋得出這種城堡？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……숲을 헤맨 끝에 다다른 성곽도시라. 꼭 도원경 같군요.","JPN":"……森を彷徨った末に辿り着いたのが城郭都市ですか。まるで桃源郷のようですね。","ENG":"A walled city at the edge of a forest, huh… It's like something straight out of a fairy tale.","TWN":"森林的盡頭是城邑……彷彿世外桃源一樣。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"성곽도시? 그게 뭐야?","JPN":"城郭都市？　なにそれ？","ENG":"Walled city? What exactly is that?","TWN":"城邑？那是什麼？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저렇게 내성을 중심으로 도시가 조성되고, 그 밖을 외성으로 감싼 구조예요.","JPN":"あのように城を中心に都市を造り、その外側を城壁で囲んだ構造のことです。","ENG":"It's where a town is surrounded by a protective screen of walls, like this.","TWN":"就是以一個城堡為中心產生都市聚落，外面還有城牆環繞。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 것도 알고 있다니 대단하네…….","JPN":"そんなことまで知っているなんてすごいね……","ENG":"How do you know all that? That's impressive.","TWN":"你竟然連這個都知道，真厲害……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회장은 원래 건축물에도 관심이 많은 거야?","JPN":"会長は元々建築にも興味があったの？","ENG":"Are you into architecture or something?","TWN":"會長本來就對建築很有興趣嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아뇨. TRPG 동아리장에게 배운 지식이에요.","JPN":"いいえ。TRPGのサークルリーダーから教えてもらいました。","ENG":"No. I learned it from the Chairman of the Tabletop RPG Club.","TWN":"不，是TRPG社團的社長告訴我的。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"유명 룰북인 <color=#ffd34c>던전 앤 카운터즈</color>에서 일반적인 주거 형태라더군요.","JPN":"有名なルールブック<color=#ffd34c>ダンジョン&カウンターズ</color>によると一般的な住居形態だそうです。","ENG":"It's a common style of residence in <color=#ffd34c>Dungeon and Counters</color>.","TWN":"據說在知名玩家手冊 <color=#ffd34c>龍與制裁者</color>中，這是一般的居住型態。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"TRPG?","JPN":"TRPG？","ENG":"Tabletop RPG?","TWN":"TRPG？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 자신의 캐릭터를 만들어서 대화를 통해 각자 역할을 수행하는 보드 게임의 일종이죠.","JPN":"はい。自分のキャラクターを作って、会話によってそれぞれの役割を果たすテーブルゲームの一種です。","ENG":"That's right. It's a sort of a boardgame where you roleplay as different characters through dice and dialog.","TWN":"就是扮演一個角色，透過對話運用各自的能力進行遊戲。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"활동 점검차 방문했을 때 동아리장이 권유해서 플레이를 해 본 적이 있는데, 무척 즐거웠어요.","JPN":"サークル活動監査のために訪ねた時、\\nサークルリーダーに勧められてプレイをしてみたことがあるのですが、とても楽しかったです。","ENG":"I had a chance to play it when I was visiting each club to inspect their activities... And it was quite enjoyable.","TWN":"進行評鑑社團時，在社長的推薦之下有玩過，很好玩喔！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 그 때 회장님이 던지는 주사위마다 더블 1만 나와서 파티가 몇 번이나 전멸했다던데…….","JPN":"あ、あの時会長が毎回サイコロを投げるたびに、\\nサイコロが2つとも1ばかり出てパーティーが何度も全滅したらしくて……","ENG":"Oh, I heard that your party got wiped several times because you kept rolling snake eyes…","TWN":"哦～聽說那時候會長每次都擲到1，好幾次都差點害團隊全軍覆沒……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"마지막에 결국 우셨다는 소문, 사실은 아니죠?","JPN":"最後は泣いてしまったという噂は、事実じゃないですよね？","ENG":"Rumor has it that you cried in the end. That's not true, is it?","TWN":"最後好像還哭咧？這應該只是謠傳吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"크흠. 기억이 잘 안 나네요.","JPN":"こほん。ちょっと覚えていませんね。","ENG":"Ahem. I'm not sure if I remember such a thing.","TWN":"咳咳，我沒印象了。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"어쨌든 이 정도 규모라면 역사적으로도 손꼽히는 대도시 이상입니다.","JPN":"とにかく、この規模なら歴史的にも指折りの大都市です。","ENG":"In any case, a castle this big is of a historic scale, I must say.","TWN":"回到正題，像這種規模的建築，在歷史上也是屈指可數。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만……. 역시 이상하네요.","JPN":"しかし……やはりおかしいですね。","ENG":"However… Something's not right.","TWN":"果然……事有蹊蹺！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이상하다니, 뭐가?","JPN":"おかしいってなにが？","ENG":"What do you mean?","TWN":"哪裡奇怪？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저기를 보세요. 도시를 절반으로 자른 듯이 경계 너머에는 아무것도 없어요.","JPN":"あそこを見てください。都市を半分に切ったかのように、境界の向こう側は何もありません。","ENG":"Look over there. There's nothing beyond that boundary; it’s as if they sliced the city clean in half.","TWN":"你看，到那邊後，好像城市被切成兩半一樣，另一邊什麼都沒有。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"마치 원래 있던 도시의 일부분만 옮겨 놓은 것처럼.","JPN":"まるで、元の都市の一部だけを移してきたかのように。","ENG":"Or they transplanted only a part of an already existing city.","TWN":"好像只是將城市的一部分原封不動地搬過來這裡一樣。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 일이 가능해?","JPN":"そんなことってできるの？","ENG":"Is such a thing possible?","TWN":"這有可能嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아뇨. 제가 아는 한 불가능해요.","JPN":"いいえ、私が知る限りでは不可能です。","ENG":"No. Not as far as I know.","TWN":"在我的認知裡是不可能的，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이 정도 규모의 도시를 옮길 수 있는 공간 조작 기술이 존재한다면 모르겠지만요.","JPN":"この規模の都市を移せるほどの空間操作技術が存在するならわかりませんが。","ENG":"Unless, of course, someone or something capable of spatial manipulation can move a city that large.","TWN":"但如果有可以搬動這種規模城市的空間操控技術，也是不無可能。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"공간 조작이라…… 평범한 사람이 할 수 있는 일은 아니지.","JPN":"空間操作か……普通の人にできることではないね。","ENG":"Spatial manipulation, huh… That definitely doesn't sound easy.","TWN":"空間操控……不是普通人可以辦得到的吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일단은 도시에 들어가 보자. 뭔가 다른 단서가 있을지도 몰라.","JPN":"とりあえず都市に入ってみよう。なにか手がかりがあるかもしれない。","ENG":"Why don't we just enter the city for now? We might find other leads inside.","TWN":"總之就先進去看看吧！或許會有其他線索。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"잠깐, 너 지금까지 뭘 들은 거야? 자칫하면…….","JPN":"まって、今まで何を聞いてたの？　下手したら……","ENG":"Hang on, were you even listening? What if you…","TWN":"等等，你沒聽到剛才他說的嗎？要是就這樣貿然闖進，萬一……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"찾았다. 숲이 시끄럽던 이유가 여기 있었군.","JPN":"見つけたぞ。森がざわついていた理由はこれだったのか。","ENG":"I've spotted them. So, this was the cause behind the commotion in the woods.","TWN":"找到了！我還想說森林裡怎麼這麼吵？兇手就是你們！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"누구냐, 너희들은.","JPN":"君たちは何者だ。","ENG":"Who art thou?","TWN":"來者何人！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};